     1→//! Statistical inference tools for computing standard errors and hypothesis tests
     2→//!
     3→//! This crate provides centralized tools for statistical inference, including
     4→//! standard errors, p-values, confidence intervals, and robust covariance
     5→//! estimators (e.g., sandwich estimators HC0-HC3).
     6→
     7→#![forbid(unsafe_code)]
     8→#![warn(missing_docs)]
     9→
    10→use ndarray::Array2;
    11→
    12→/// Statistical inference errors
    13→#[derive(thiserror::Error, Debug)]
    14→pub enum InferenceError {
    15→    /// Matrix computation error
    16→    #[error("Matrix computation error: {0}")]
    17→    Matrix(String),
    18→    /// Invalid degrees of freedom
    19→    #[error("Invalid degrees of freedom: {0}")]
    20→    DegreesOfFreedom(i32),
    21→}
    22→
    23→/// Compute standard errors from variance-covariance matrix
    24→pub fn standard_errors(vcov: &Array2<f64>) -> Vec<f64> {
    25→    let mut se = Vec::new();
    26→    for i in 0..vcov.nrows() {
    27→        se.push(vcov[[i, i]].sqrt());
    28→    }
    29→    se
    30→}
    31→
    32→/// Compute t-statistics given coefficients and standard errors  
    33→pub fn t_statistics(coefficients: &[f64], std_errors: &[f64]) -> Vec<f64> {
    34→    coefficients
    35→        .iter()
    36→        .zip(std_errors.iter())
    37→        .map(|(coef, se)| coef / se)
    38→        .collect()
    39→}
    40→
    41→/// Compute two-tailed p-values from t-statistics
    42→pub fn t_test_p_values(t_stats: &[f64], df: i32) -> Vec<f64> {
    43→    t_stats
    44→        .iter()
    45→        .map(|&t| {
    46→            // Two-tailed p-value: P(|T| > |t|) = 2 * P(T > |t|)
    47→            let abs_t = t.abs();
    48→            2.0 * (1.0 - t_cdf(abs_t, df))
    49→        })
    50→        .collect()
    51→}
    52→
    53→/// Cumulative distribution function for Student's t-distribution
    54→/// Uses the relationship: t_cdf(t, df) = 1/2 + t * gamma((df+1)/2) / (sqrt(pi*df) * gamma(df/2)) * F(1/2, (df+1)/2; 3/2; -t²/df)
    55→/// Where F is the hypergeometric function. For practical purposes, we use the beta distribution relationship.
    56→fn t_cdf(t: f64, df: i32) -> f64 {
    57→    if df <= 0 {
    58→        return 0.5; // Invalid df, return neutral p-value
    59→    }
    60→
    61→    if t.is_infinite() {
    62→        return if t > 0.0 { 1.0 } else { 0.0 };
    63→    }
    64→
    65→    // For large df (>= 30), approximate with standard normal
    66→    if df >= 30 {
    67→        return standard_normal_cdf(t);
    68→    }
    69→
    70→    // Use the relationship between t-distribution and beta distribution
    71→    // If T ~ t(df), then (T² / (T² + df)) ~ Beta(1/2, df/2)
    72→    let df_f = df as f64;
    73→    let x = t * t / (t * t + df_f);
    74→
    75→    if t >= 0.0 {
    76→        0.5 + 0.5 * incomplete_beta(0.5, df_f / 2.0, x)
    77→    } else {
    78→        0.5 - 0.5 * incomplete_beta(0.5, df_f / 2.0, x)
    79→    }
    80→}
    81→
    82→/// Standard normal CDF approximation using rational approximation
    83→fn standard_normal_cdf(x: f64) -> f64 {
    84→    // Abramowitz and Stegun approximation 7.1.26
    85→    let a1 = 0.254829592;
    86→    let a2 = -0.284496736;
    87→    let a3 = 1.421413741;
    88→    let a4 = -1.453152027;
    89→    let a5 = 1.061405429;
    90→    let p = 0.3275911;
    91→
    92→    let sign = if x < 0.0 { -1.0 } else { 1.0 };
    93→    let x = x.abs() / 2.0_f64.sqrt();
    94→
    95→    let t = 1.0 / (1.0 + p * x);
    96→    let y = 1.0 - (((((a5 * t + a4) * t) + a3) * t + a2) * t + a1) * t * (-x * x).exp();
    97→
    98→    0.5 * (1.0 + sign * y)
    99→}
   100→
   101→/// Incomplete beta function approximation
   102→/// This is a simplified implementation - a full implementation would use continued fractions
   103→fn incomplete_beta(a: f64, b: f64, x: f64) -> f64 {
   104→    if x <= 0.0 {
   105→        return 0.0;
   106→    }
   107→    if x >= 1.0 {
   108→        return 1.0;
   109→    }
   110→
   111→    // For small parameters, use a simple series approximation
   112→    // This is not highly accurate but sufficient for basic statistical inference
   113→    let mut result = 0.0;
   114→    let mut term = x.powf(a) * (1.0 - x).powf(b) / (a * beta_function(a, b));
   115→
   116→    for n in 0..50 {
   117→        result += term;
   118→        term *= x * (a + n as f64) / ((a + b + n as f64) * (n as f64 + 1.0));
   119→        if term.abs() < 1e-10 {
   120→            break;
   121→        }
   122→    }
   123→
   124→    result.min(1.0)
   125→}
   126→
   127→/// Beta function B(a, b) = Γ(a)Γ(b)/Γ(a+b)
   128→/// Approximation using logarithmic gamma function
   129→fn beta_function(a: f64, b: f64) -> f64 {
   130→    (log_gamma(a) + log_gamma(b) - log_gamma(a + b)).exp()
   131→}
   132→
   133→/// Logarithmic gamma function approximation using Stirling's formula
   134→fn log_gamma(x: f64) -> f64 {
   135→    if x < 1.0 {
   136→        return log_gamma(x + 1.0) - x.ln();
   137→    }
   138→
   139→    // Stirling's approximation: ln(Γ(x)) ≈ (x - 0.5) * ln(x) - x + 0.5 * ln(2π)
   140→    (x - 0.5) * x.ln() - x + 0.5 * (2.0 * std::f64::consts::PI).ln()
   141→}
   142→
   143→/// Compute F-statistic p-value using F-distribution
   144→///
   145→/// For F(f; df1, df2) = P(F ≤ f), where F follows F-distribution with df1, df2 degrees of freedom
   146→pub fn f_test_p_value(f_stat: f64, df1: i32, df2: i32) -> f64 {
   147→    if f_stat <= 0.0 || df1 <= 0 || df2 <= 0 {
   148→        return 1.0;
   149→    }
   150→
   151→    // F distribution p-value: P(F > f_stat) = 1 - I_x(df1/2, df2/2)
   152→    // where x = df1*f_stat / (df1*f_stat + df2) and I is regularized incomplete beta function
   153→    let x = (df1 as f64 * f_stat) / (df1 as f64 * f_stat + df2 as f64);
   154→    let a = df1 as f64 / 2.0;
   155→    let b = df2 as f64 / 2.0;
   156→
   157→    1.0 - incomplete_beta(a, b, x)
   158→}
   159→
   160→/// Calculate overall F-statistic for model significance
   161→/// Tests null hypothesis that all non-intercept coefficients are zero
   162→pub fn model_f_statistic(rss_full: f64, rss_null: f64, df_model: usize, df_resid: usize) -> f64 {
   163→    if df_model == 0 || df_resid == 0 || rss_full <= 0.0 {
   164→        return 0.0;
   165→    }
   166→
   167→    let explained_ss = rss_null - rss_full;
   168→    let mse_model = explained_ss / df_model as f64;
   169→    let mse_resid = rss_full / df_resid as f64;
   170→
