/// Incomplete beta function approximation
/// This is a simplified implementation - a full implementation would use continued fractions
fn incomplete_beta(a: f64, b: f64, x: f64) -> f64 {
    if x <= 0.0 {
        return 0.0;
    }
    if x >= 1.0 {
        return 1.0;
    }

    // For small parameters, use a simple series approximation
    // This is not highly accurate but sufficient for basic statistical inference
    let mut result = 0.0;
    let mut term = x.powf(a) * (1.0 - x).powf(b) / (a * beta_function(a, b));

    for n in 0..50 {
        result += term;
        term *= x * (a + n as f64) / ((a + b + n as f64) * (n as f64 + 1.0));
        if term.abs() < 1e-10 {
            break;
        }
    }

    result.min(1.0)
}

