use criterion::{criterion_group, criterion_main, Criterion};
use stats_models::Lm;

fn benchmark_lm_fit(c: &mut Criterion) {
    // Generate identity matrix data as flattened vec
    let n_obs = 100;
    let n_vars = 100;
    let mut x_data = vec![0.0; n_obs * n_vars];

    // Create identity matrix
    for i in 0..n_obs {
        for j in 0..n_vars {
            if i == j {
                x_data[i * n_vars + j] = 1.0;
            }
        }
    }

    let y = vec![1.0; n_obs];

    c.bench_function("lm_fit_100x100", |b| {
        b.iter(|| {
            let _fit = Lm::fit(&x_data, &y, n_obs, n_vars).unwrap();
        })
    });
}

criterion_group!(benches, benchmark_lm_fit);
criterion_main!(benches);

//! Exponential family distributions for generalized linear models
//!
//! This crate provides family structs that specify variance functions and
//! default link functions for GLM fitting.

#![forbid(unsafe_code)]
#![warn(missing_docs)]

use link::{Identity, LinkFn, Log, Logit};

/// Trait for exponential family distributions
pub trait Family {
    /// Associated link function type
    type Link: LinkFn;

    /// Variance function V(μ)
    fn variance(&self, mu: f64) -> f64;

    /// Default link function
    fn link(&self) -> Self::Link;

// R-style formula grammar for pest parser
// Supports basic formula syntax: y ~ x1 + x2*x3

WHITESPACE = _{ " " | "\t" | "\n" | "\r" }

// Top-level formula structure
formula = { SOI ~ response ~ "~" ~ terms ~ EOI }

// Response variable (left side of ~)
response = { variable }

// Right side terms (predictors)
terms = { term ~ ("+" ~ term)* }

// Individual term (variable or interaction)
term = { interaction | variable | "1" }

// Interaction term (x1*x2 or x1:x2)
interaction = { variable ~ ("*" | ":") ~ variable ~ ("*" ~ variable | ":" ~ variable)* }

// Variable name (R identifier rules)
variable = { ASCII_ALPHA ~ (ASCII_ALPHANUMERIC | "_" | ".")* }

// Number (for intercept specification)
number = { ASCII_DIGIT+ }

