//! High-performance design matrix construction for statistical models
//!
//! This crate provides column-oriented design matrix builders that fuse
//! transformations to eliminate intermediate allocations and leverage
//! parallel computation for construction.

#![forbid(unsafe_code)]
#![warn(missing_docs)]

use formula::ModelSpec;
use ndarray::Array2;
use std::collections::HashMap;

/// Design matrix construction errors
#[derive(thiserror::Error, Debug)]
pub enum MatrixError {
    /// Data dimension mismatch
    #[error("Data dimension error: {0}")]
    Dimension(String),
    /// Variable not found in data
    #[error("Variable not found: {0}")]
    VariableNotFound(String),
}

/// Column-major design matrix builder
pub struct Builder {
    n_rows: usize,
    columns: Vec<Vec<f64>>,
}

impl Builder {
    /// Create a new builder for the given number of observations
    pub fn new(n_rows: usize) -> Self {
        Self {
            n_rows,
            columns: Vec::new(),
        }
    }

    /// Add an intercept column (all ones)
    pub fn add_intercept(&mut self) {
        self.columns.push(vec![1.0; self.n_rows]);
    }

    /// Add a continuous variable column
    pub fn add_continuous(&mut self, values: Vec<f64>) -> Result<(), MatrixError> {
        if values.len() != self.n_rows {
            return Err(MatrixError::Dimension(format!(
                "Expected {} rows, got {}",
                self.n_rows,
                values.len()
            )));
        }
        self.columns.push(values);
        Ok(())
    }

    /// Build the final design matrix
    pub fn build(self) -> Array2<f64> {
        if self.columns.is_empty() {
            return Array2::zeros((self.n_rows, 0));
        }

        let n_cols = self.columns.len();
        let mut matrix = Array2::zeros((self.n_rows, n_cols));

        for (col_idx, column) in self.columns.into_iter().enumerate() {
            for (row_idx, value) in column.into_iter().enumerate() {
                matrix[[row_idx, col_idx]] = value;
            }
        }

        matrix
    }
}

/// Data container for building design matrices
#[derive(Debug)]
pub struct DataContainer {
    variables: std::collections::HashMap<String, Vec<f64>>,
    n_rows: usize,
}

impl DataContainer {
    /// Create a new data container
    pub fn new(n_rows: usize) -> Self {
        Self {
            variables: std::collections::HashMap::new(),
            n_rows,
        }
    }

    /// Add a continuous variable to the data
    pub fn add_variable(&mut self, name: String, values: Vec<f64>) -> Result<(), MatrixError> {
        if values.len() != self.n_rows {
            return Err(MatrixError::Dimension(format!(
                "Variable '{}' has {} values but expected {}",
                name,
                values.len(),
                self.n_rows
            )));
        }
        self.variables.insert(name, values);
        Ok(())
    }

    /// Get a variable by name
    pub fn get_variable(&self, name: &str) -> Option<&Vec<f64>> {
        self.variables.get(name)
    }
}

/// Build design matrix from model specification and data
pub fn build_design_matrix(spec: &ModelSpec, data: &DataContainer) -> Result<Array2<f64>, MatrixError> {
    use formula::Term;

    let mut builder = Builder::new(data.n_rows);
    let mut column_names = Vec::new();

    // Process each term in the model specification
    for term in &spec.terms {
        match term {
            Term::Intercept => {
                builder.add_intercept();
                column_names.push("(Intercept)".to_string());
            }
            Term::Variable(var_name) => {
                let values = data.get_variable(var_name)
                    .ok_or_else(|| MatrixError::VariableNotFound(var_name.clone()))?;
                builder.add_continuous(values.clone())?;
                column_names.push(var_name.clone());
            }
            Term::Interaction(vars) => {
                // For interaction terms, multiply the variables together
                if vars.len() < 2 {
                    return Err(MatrixError::Dimension(
                        "Interaction term must have at least 2 variables".to_string()
                    ));
                }

                // Get the first variable
                let first_var = match &vars[0] {
                    Term::Variable(name) => data.get_variable(name)
                        .ok_or_else(|| MatrixError::VariableNotFound(name.clone()))?,
                    _ => return Err(MatrixError::Dimension(
                        "Interaction terms must contain variable names".to_string()
                    )),
                };

                // Start with the first variable's values
                let mut interaction_values = first_var.clone();
                let mut interaction_name = match &vars[0] {
                    Term::Variable(name) => name.clone(),
                    _ => unreachable!(),
                };

                // Multiply by each subsequent variable
                for var in &vars[1..] {
                    match var {
                        Term::Variable(name) => {
                            let var_values = data.get_variable(name)
                                .ok_or_else(|| MatrixError::VariableNotFound(name.clone()))?;

                            for (i, value) in interaction_values.iter_mut().enumerate() {
                                *value *= var_values[i];
                            }
                            interaction_name.push(':');
                            interaction_name.push_str(name);
                        }
                        _ => return Err(MatrixError::Dimension(
                            "Interaction terms must contain variable names".to_string()
                        )),
                    }
                }

                builder.add_continuous(interaction_values)?;
                column_names.push(interaction_name);
            }
            Term::Function { name: _, args: _ } => {
                // TODO: Implement function calls in future sprint
                return Err(MatrixError::Dimension(
                    "Function calls not yet implemented".to_string()
                ));
            }
        }
    }

    Ok(builder.build())
}

